import { type PropsWithChildren, type HTMLAttributes } from 'react';

import { secondaryInfo } from './styles.sty.js';

/** @internal */
export type SecondaryAtomProps = PropsWithChildren<
  HTMLAttributes<HTMLDivElement>
>;

/**
 * @internal
 **/
export const SecondaryAtom = ({ children, ...rest }: SecondaryAtomProps) => {
  return (
    <div className={secondaryInfo} {...rest}>
      {children}
    </div>
  );
};
SecondaryAtom['displayName'] = 'SecondaryAtom';
